import{_ as a,o as i,c as e,ag as n}from"./chunks/framework.gU7RhlGX.js";const u=JSON.parse('{"title":"🚀 2026 开发者必装：Claude Code 七大神技","description":"","frontmatter":{},"headers":[],"relativePath":"skills/2026skills.md","filePath":"skills/2026skills.md","lastUpdated":1776422487000}'),l={name:"skills/2026skills.md"};function t(r,s,p,h,d,o){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="🚀-2026-开发者必装-claude-code-七大神技" tabindex="-1">🚀 2026 开发者必装：Claude Code 七大神技 <a class="header-anchor" href="#🚀-2026-开发者必装-claude-code-七大神技" aria-label="Permalink to &quot;🚀 2026 开发者必装：Claude Code 七大神技&quot;">​</a></h1><p>这些技能能让你的 Claude 从“普通 AI”直接进化为“顶级架构师”和“全能助手”。</p><hr><h3 id="_1-超级引擎-superpowers" tabindex="-1">1. 超级引擎 (Superpowers) <a class="header-anchor" href="#_1-超级引擎-superpowers" aria-label="Permalink to &quot;1. 超级引擎 (Superpowers)&quot;">​</a></h3><p>⭐ 140.3k stars · <a href="https://github.com/obra/superpowers" target="_blank" rel="noreferrer">github.com/obra/superpowers</a></p><p>Claude 默认往往会直接闷头写代码。<strong>Superpowers</strong> 强行让它停下来：先思考、再计划、最后才写代码。</p><p>它会自动强制执行：<strong>头脑风暴 → 整体规划 → TDD（测试驱动开发）→ 代码审查</strong>流程。无需繁琐配置，装完即刻生效。</p><ul><li><strong>推荐场景：</strong> 任何如果你受够了 AI “瞎写”导致代码乱糟糟的项目。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> original/superpowers-marketplace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> superpowers@superpowers-marketplace</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h3 id="_2-记忆芯片-claude-mem" tabindex="-1">2. 记忆芯片 (Claude Mem) <a class="header-anchor" href="#_2-记忆芯片-claude-mem" aria-label="Permalink to &quot;2. 记忆芯片 (Claude Mem)&quot;">​</a></h3><p>⭐ 46.5k stars · <a href="https://github.com/thedotmack/claude-mem" target="_blank" rel="noreferrer">github.com/thedotmack/claude-mem</a></p><p>对话一结束后，Claude 就会“选择性失忆”。这个技能就是专门给它补脑的。</p><p>它能捕捉 Claude 在聊天中学到的知识，自动压缩并存入下次对话。你的项目背景、个人偏好、重要决策都能永久保留。它甚至提供了一个本地查看器 (<a href="http://localhost:37777" target="_blank" rel="noreferrer">http://localhost:37777</a>)，让你一眼看到它到底记住了啥。</p><ul><li><strong>推荐场景：</strong> 需要跨越多次对话、长期推进的复杂大项目。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thedotmack/claude-mem</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude-mem</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h3 id="_3-技能宝库-awesome-claude-code" tabindex="-1">3. 技能宝库 (Awesome Claude Code) <a class="header-anchor" href="#_3-技能宝库-awesome-claude-code" aria-label="Permalink to &quot;3. 技能宝库 (Awesome Claude Code)&quot;">​</a></h3><p>⭐ 32.6k stars · <a href="https://github.com/hesreallyhim/awesome-claude-code" target="_blank" rel="noreferrer">github.com/hesreallyhim/awesome-claude-code</a></p><p>这不是一个要安装的技能，而是一个你开工前必须刷一遍的“藏经阁”。</p><p>这里汇集了所有值得一用的技能、插件、钩子和工具。全是人工精选，绝非 AI 水文。动手写代码前花 5 分钟扫一眼，往往能帮你省下数小时的弯路。</p><ul><li><strong>推荐场景：</strong> 在你亲自动手造轮子之前，先来看看有没有现成的“超级轮子”。</li></ul><hr><h3 id="_4-审美大师-ui-ux-pro-max" tabindex="-1">4. 审美大师 (UI/UX Pro Max) <a class="header-anchor" href="#_4-审美大师-ui-ux-pro-max" aria-label="Permalink to &quot;4. 审美大师 (UI/UX Pro Max)&quot;">​</a></h3><p>⭐ 61.5k stars · <a href="https://github.com/nextlevelbuilder/ui-ux-pro-max-skill" target="_blank" rel="noreferrer">github.com/nextlevelbuilder/ui-ux-pro-max-skill</a></p><p>别再让 Claude 写的 Web 应用看起来都一个样了（那个浓浓的、廉价的 AI 味）。</p><p>这个技能为 Claude 注入了 50 多种 UI 风格、97 套顶级调色盘和 57 种字体组合。它会自动根据你的项目调性选择最搭的设计系统。无论是 React、Next.js 还是 Tailwind，都能拿捏得死死的。</p><ul><li><strong>推荐场景：</strong> 任何需要“见人”的前端项目，让你的 UI 瞬间高级起来。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nextlevelbuilder/ui-ux-pro-max-skill</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ui-ux-pro-max@ui-ux-pro-max-skill</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h3 id="_5-obsidian-伴侣" tabindex="-1">5. Obsidian 伴侣 <a class="header-anchor" href="#_5-obsidian-伴侣" aria-label="Permalink to &quot;5. Obsidian 伴侣&quot;">​</a></h3><p>⭐ 21.8k stars · <a href="https://github.com/kepano/obsidian-skills" target="_blank" rel="noreferrer">github.com/kepano/obsidian-skills</a></p><p>由 Obsidian 掌门人亲手打造。教 Claude 真正理解 Obsidian 的规则。</p><p>没有它，Claude 只会写死板的 Markdown，可能会搞坏 WikiLinks 或无视 Canvas 语法。有了它，Claude 就能帮你打理笔记库：从创建关联笔记到构建画布图谱，都不在话下。</p><ul><li><strong>推荐场景：</strong> 重度依赖 Obsidian 的开发者，让 Claude 真正“住进”你的知识库。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com:kepano/obsidian-skills.git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="_6-n8n-自动化助手" tabindex="-1">6. n8n 自动化助手 <a class="header-anchor" href="#_6-n8n-自动化助手" aria-label="Permalink to &quot;6. n8n 自动化助手&quot;">​</a></h3><p>⭐ 17.7k stars · <a href="https://github.com/czlonkowski/n8n-mcp" target="_blank" rel="noreferrer">github.com/czlonkowski/n8n-mcp</a></p><p>Claude 对 n8n 节点名一无所知？用了它，它就是 n8n 的“活百科”。</p><p>它掌握 1200+ 节点的名称、参数和架构细节。以前需要折腾 45 分钟才能调通的自动化流，现在 3 分钟起飞。它通过 MCP 协议让 Claude 在构建工作流时实时查询文档。</p><ul><li><strong>推荐场景：</strong> 任何涉及 n8n 工作流自动化的项目。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> n8n-mcp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MCP_MODE=stdio</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> n8n-mcp</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h3 id="_7-搞定一切-gsd-—-get-shit-done" tabindex="-1">7. 搞定一切 (GSD — Get Shit Done) <a class="header-anchor" href="#_7-搞定一切-gsd-—-get-shit-done" aria-label="Permalink to &quot;7. 搞定一切 (GSD — Get Shit Done)&quot;">​</a></h3><p>⭐ 49.6k stars · <a href="https://github.com/glittercowboy/get-shit-done" target="_blank" rel="noreferrer">github.com/glittercowboy/get-shit-done</a></p><p>只需一个指令，Claude 直接变身“卷王级”项目经理。</p><p>它会全程带你：<strong>调研 → 整理需求 → 制定路线图</strong>，然后分阶段派发任务给子智能体执行。前一步没验证通过，坚决不跑下一步。专为讨厌繁文缛节、追求极致执行力的独立开发打造。</p><ul><li><strong>推荐场景：</strong> 刚有一个 Idea 的“毛坯房”项目，需要先打好地基。</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get-shit-done-cc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --claude</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 然后输入指令启动：</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/gsd:new-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="🛠️-你的神级工作流建议" tabindex="-1">🛠️ 你的神级工作流建议 <a class="header-anchor" href="#🛠️-你的神级工作流建议" aria-label="Permalink to &quot;🛠️ 你的神级工作流建议&quot;">​</a></h2><p>这些技能不是竞争关系，而是“叠 Buff”的关系：</p><ol><li><strong>开工前：</strong> 先检查 <strong>Awesome Claude Code</strong>，看看有没有现成的利器。</li><li><strong>准备阶段：</strong> 装好 <strong>Claude Mem</strong> 存好上下文，选择 <strong>Superpowers</strong> 或 <strong>GSD</strong> 定好节奏。</li><li><strong>开发中：</strong> 写 Web 就配 <strong>UI/UX Pro Max</strong>；搞自动化就加 <strong>n8n-MCP</strong>；记笔记就上 <strong>Obsidian Skills</strong>。</li></ol><p>用不用这些技能，决定了你是和 Claude 在一起“挣扎”，还是在一起“起飞”。</p>`,55)])])}const c=a(l,[["render",t]]);export{u as __pageData,c as default};
